const item = $input.first().json;
const conversationId = item.conversation_id || item[0] || 'unknown';
const playerId       = item.player_id       || item[1] || 'unknown';
const agentName      = item.agent_name      || item[2] || 'Unknown';
const transcript     = String(item.transcript ?? item[3] ?? '');
const intercomLink   = item.intercom_link   || item[8] || '';
const isBotHandled   = item.is_bot_handled === true;

if (!transcript || transcript.trim().length === 0) {
  throw new Error(`Empty transcript for conversation ${conversationId} — skipping`);
}

const MAX_CHARS = 60000;
const truncated = transcript.length > MAX_CHARS
  ? transcript.substring(0, MAX_CHARS) + '\n\n[Transcript truncated]'
  : transcript;

const systemPrompt = `You are an expert Quality Assurance analyst for a regulated iGaming (online casino/sports betting) customer support operation. Analyze the support conversation and return ONLY a valid JSON object — no preamble, no explanation, no markdown.

LANGUAGE HANDLING:
The conversation transcript may be in any of these languages:
Arabic (ar), German (de), Greek (el), English (en), Finnish (fi), French (fr), Italian (it), Norwegian (no), or Portuguese (pt).
Detect the language of the conversation and return it as an ISO 639-1 code in the "language" field.
ALL other output fields (summary, agent_performance_notes, recommended_action, key_quotes, alert_reason, etc.) must be written in English regardless of the conversation language.

SEVERITY (dissatisfaction_severity):
- "Low"      — Minor frustration, issue fully resolved, player tone normalized
- "Medium"   — Clear dissatisfaction, partially resolved or player still uneasy
- "High"     — Strong dissatisfaction, issue unresolved, churn risk
- "Critical" — Legal/regulatory threat, VIP complaint, fraud indicators, inappropriate agent conduct

ISSUE CATEGORY (issue_category — pick exactly one):
"Payment/Withdrawal" | "Game Bug" | "Login/Account" | "Bonus/Promotion" | "Technical Error" | "Website & Navigation" | "Device & Compatibility" | "Slow Response" | "Inappropriate Communication" | "Other"

RESOLUTION STATUS (resolution_status — based on player sentiment at END of conversation, NOT Intercom status):
"Resolved" | "Partially Resolved" | "Unresolved"

AGENT PERFORMANCE SCORE (agent_performance_score):
- If Is Bot Handled is true: set agent_performance_score to null and agent_performance_notes to "N/A — conversation handled by bot"
- 5=Exceptional, 4=Good, 3=Adequate, 2=Below Standard, 1=Poor

ALERT (is_alert_worthy = true) when ANY of:
- Player mentions legal action, regulator, lawyer
- VIP or high-value player dissatisfied
- Agent used inappropriate or discriminatory language
- Fraud indicators present

Return ONLY this JSON — all fields required:
{
  "language": "ISO 639-1 code (ar|de|el|en|fi|fr|it|no|pt)",
  "summary": "1-3 sentence factual summary",
  "dissatisfaction_severity": "Low|Medium|High|Critical",
  "issue_category": "one of the 10 categories",
  "resolution_status": "Resolved|Partially Resolved|Unresolved",
  "key_quotes": "1-2 direct player quotes, comma-separated, or empty string",
  "agent_performance_score": null,
  "agent_performance_notes": "specific observation about agent performance, or N/A — conversation handled by bot",
  "recommended_action": "specific QA action or No action required",
  "is_alert_worthy": false,
  "alert_reason": null
}`;

const userMessage = `Conversation ID: ${conversationId}\nPlayer ID: ${playerId}\nAgent: ${agentName}\nIs Bot Handled: ${isBotHandled}\n\nTranscript:\n${truncated}`;

return [{
  json: {
    conversation_id: conversationId,
    player_id:       playerId,
    agent_name:      agentName,
    intercom_link:   intercomLink,
    is_bot_handled:  isBotHandled,
    model:           'claude-sonnet-4-6',
    max_tokens:      4096,
    system:          systemPrompt,
    messages: [
      { role: 'user', content: userMessage }
    ]
  }
}];

const response = $input.first().json;
const buildNode = $('Build Claude Request').first().json;

const analyzedAt = new Date().toISOString();
const isBotHandled = buildNode.is_bot_handled === true;

const VALID_LANGUAGES   = ['ar', 'de', 'el', 'en', 'fi', 'fr', 'it', 'no', 'pt'];
const VALID_SEVERITIES  = ['Low', 'Medium', 'High', 'Critical'];
const VALID_CATEGORIES  = ['Payment/Withdrawal', 'Game Bug', 'Login/Account', 'Bonus/Promotion', 'Technical Error', 'Website & Navigation', 'Device & Compatibility', 'Slow Response', 'Inappropriate Communication', 'Other'];
const VALID_RESOLUTIONS = ['Resolved', 'Partially Resolved', 'Unresolved'];

const rawContent = response.content?.[0]?.text;
if (!rawContent) {
  return [{ json: {
    _parse_error: true,
    conversation_id: buildNode.conversation_id || 'unknown',
    player_id: buildNode.player_id || 'unknown',
    agent_name: buildNode.agent_name || 'Unknown',
    intercom_link: buildNode.intercom_link || '',
    summary: '[PARSE ERROR - manual review required: no content in Claude response]',
    severity: 'Medium', issue_category: 'Other', resolution_status: 'Unresolved',
    key_quotes: '', agent_score: null, agent_notes: '', recommended_action: 'Manual review required',
    is_alert: false, alert_reason: '', is_bot_handled: isBotHandled, language: 'en', analyzed_at: analyzedAt
  } }];
}

let parsed;
try {
  parsed = JSON.parse(rawContent);
} catch (parseErr) {
  return [{ json: {
    _parse_error: true,
    conversation_id: buildNode.conversation_id || 'unknown',
    player_id: buildNode.player_id || 'unknown',
    agent_name: buildNode.agent_name || 'Unknown',
    intercom_link: buildNode.intercom_link || '',
    summary: `[PARSE ERROR - manual review required: ${parseErr.message}]`,
    severity: 'Medium', issue_category: 'Other', resolution_status: 'Unresolved',
    key_quotes: '', agent_score: null, agent_notes: '', recommended_action: 'Manual review required',
    is_alert: false, alert_reason: '', is_bot_handled: isBotHandled, language: 'en', analyzed_at: analyzedAt
  } }];
}

let agentScore;
if (isBotHandled) {
  agentScore = null;
} else {
  const raw = parsed.agent_performance_score;
  agentScore = (Number.isInteger(raw) && raw >= 1 && raw <= 5) ? raw : 5;
}

return [{ json: {
  _parse_error: false,
  conversation_id: buildNode.conversation_id || 'unknown',
  player_id: buildNode.player_id || 'unknown',
  agent_name: buildNode.agent_name || 'Unknown',
  intercom_link: buildNode.intercom_link || '',
  summary: parsed.summary || '',
  severity: VALID_SEVERITIES.includes(parsed.dissatisfaction_severity) ? parsed.dissatisfaction_severity : 'Medium',
  issue_category: VALID_CATEGORIES.includes(parsed.issue_category) ? parsed.issue_category : 'Other',
  resolution_status: VALID_RESOLUTIONS.includes(parsed.resolution_status) ? parsed.resolution_status : 'Unresolved',
  key_quotes: parsed.key_quotes || '',
  agent_score: agentScore,
  agent_notes: parsed.agent_performance_notes || '',
  recommended_action: parsed.recommended_action || '',
  is_alert: parsed.is_alert_worthy === true,
  alert_reason: parsed.alert_reason || '',
  is_bot_handled: isBotHandled,
  language: VALID_LANGUAGES.includes(parsed.language) ? parsed.language : 'en',
  analyzed_at: analyzedAt
} }];
